function prepareForHttp(text) {
  if (text === null || text === undefined) return "";
  return String(text)
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"')
    .replace(/\r\n/g, "\\n")
    .replace(/\n/g, "\\n")
    .replace(/\t/g, "\\t")
    .replace(/\*\*/g, "*")
    .trim();
}

const proyectos = $('PROJECT LIST').first().json.proyectos || {};
const nombresProyectos = Object.values(proyectos).map(p => p.split('->')[0].trim());
const LISTA = "\\n\\n• " + nombresProyectos.join("\\n• ");

const raw = $input.first().json.output || "";
const cleanRaw = raw.replace(/```(?:json)?\n?/g, '').trim();
const match = cleanRaw.match(/\{[\s\S]*\}/);

if (!match) {
  return [{ 
    json: { 
      respuesta: "Lo siento, tuve un problema procesando esa respuesta. ¿Puedes repetirlo?",
      accion_tipo: "error",
      error: "no_json",
      raw_output: raw
    }
  }];
}

try {
  const parsed = JSON.parse(match[0]);

  const respuesta = String(parsed.respuesta || "");
  const accionTipo = parsed.accion?.tipo || "esperar";
  const transferir = parsed.estado_proyecto?.transferir ?? 0;
  const proyecto = parsed.estado_proyecto?.proyecto || null;

  // Agrega lista solo cuando pide elegir proyecto y no hay proyecto aún
  const agregarLista = accionTipo === "aclarar" && (!proyecto || respuesta.includes("proyectos disponibles actualmente"));

  const respuestaFinal = agregarLista 
    ? prepareForHttp(respuesta) + LISTA
    : prepareForHttp(respuesta);

  return [{
    json: {
      respuesta: respuestaFinal,
      accion_tipo: accionTipo,
      accion_razon: parsed.accion?.razon || "",
      proyecto: proyecto,
      transferir: transferir,
      lead_nombre: parsed.estado_lead?.nombre || null,
      lead_primer_nombre: parsed.estado_lead?.primer_nombre || null,
      lead_apellidos: parsed.estado_lead?.apellidos || null,
      lead_correo: parsed.estado_lead?.correo || null,
      lead_telefono: parsed.estado_lead?.telefono || null,
      datos_completos: parsed.estado_lead?.datos_completos ?? false,
      intencion: parsed.metadatos?.intencion || null,
      idioma: parsed.metadatos?.idioma || null,
      confianza: parsed.metadatos?.confianza || null,
      herramientas_usadas: parsed.depuracion?.herramientas_usadas || [],
      ruta_decision: parsed.depuracion?.ruta_decision || "",
      advertencias: parsed.depuracion?.advertencias || [],
      raw: parsed,
      consulta_pendiente_guardar: parsed.consulta_pendiente?.guardar || null,
      consulta_pendiente_limpiar: parsed.consulta_pendiente?.limpiar || false,
      consulta_pendiente_retomar: parsed.consulta_pendiente?.retomar || null,
    }
  }];

} catch(e) {
  return [{ 
    json: { 
      respuesta: "Lo siento, tuve un problema procesando esa respuesta. ¿Puedes repetirlo?",
      accion_tipo: "error",
      error: "parse_failed",
      error_message: e.message,
      raw_output: raw
    }
  }];
}

