// 1. Capturar texto base y canal
const body = $('PARSE BODY').first().json.current_body;
const canal_ingreso = body.custom_fields?.canal_ingreso || "WhatsApp";
let message_text = body.last_input_text || "";
const message_lower = message_text.toLowerCase();

// 2. Determinar Código CRM Base (UTM Source numérico)
let utm_base = "100000004"; // Default WhatsApp
if (canal_ingreso.includes("Instagram")) utm_base = "100000012";
else if (canal_ingreso.includes("Messenger")) utm_base = "100000005";

// 3. Mapeo de Atribución basado en "Prefilled Text" (Tu tabla)
let defaultTag = "Web";
let defaultMedio = "Página web";
if (canal_ingreso.includes("Instagram") || canal_ingreso.includes("Messenger")) {
  defaultTag = "Social Media";
  defaultMedio = "Redes sociales Orgánico";
}

let atribucion = {
  tag: defaultTag,
  medio: defaultMedio,
  contacto: "Chatbot"
};

// Detección por frases exactas
if (message_lower.includes("en un anuncio")) {
  atribucion = { tag: "City Core", medio: "Comunicación en City Cores", contacto: "Chatbot" };
} else if (message_lower.includes("redes sociales")) {
  atribucion = { tag: "Social Media", medio: "Redes sociales Orgánico", contacto: "Chatbot" };
} else if (message_lower.includes("fan page")) {
  atribucion = { tag: "Fan Page", medio: "Encabezado de fan page", contacto: "Chatbot/Página web" };
} else if (message_lower.includes("por email")) {
  atribucion = { tag: "Mail", medio: "Mailings", contacto: "Chatbot" };
} else if (message_lower.includes("en el banco")) {
  atribucion = { tag: "Banco", medio: "Bancos", contacto: "Chatbot" };
} else if (message_lower.includes("quiero información") || message_lower.includes("info de")) {
  atribucion = { tag: "Web", medio: "Página web", contacto: "Chatbot" };
}

// 4. Detección de Proyectos (Mantenemos la lógica actual)
let proyecto = null;
if (message_lower.includes("vista verde") || message_lower.includes("pvv")) proyecto = "PVV";
else if (message_lower.includes("mariscal") || message_lower.includes("pmar")) proyecto = "PMAR";
else if (message_lower.includes("portales") || message_lower.includes("ppo")) proyecto = "PPO";
else if (message_lower.includes("polanco") || message_lower.includes("ppol")) proyecto = "PPOL";
else if (message_lower.includes("soto bosque") || message_lower.includes("sotobosque") ||
  message_lower.includes("psb")) proyecto = "PSB";

return [{
    json: {
        ...$input.first().json,
        extracted_campaign_data: {
            proyecto_detectado: proyecto,
            utm_source_crm: utm_base,
            // Nuevos campos detallados
            atribucion_tag: atribucion.tag,
            atribucion_medio: atribucion.medio,
            atribucion_contacto: atribucion.contacto
        }
    }
}];

